INSERT INTO public.photos VALUES (25415, 'Râ”œÂ¡o Huerva 1927', 'Vista de 1927 del entonces vial sin nombre, o Sector 2 del cubrimiento del Huerva (Puente de Santa Engracia-Paseo de la Mina), despuâ”œÂ®s Marina Moreno. A la izquierda, el edificio del colegio de los PP. Jesuitas. A la derecha, las traseras de los hotelitos de la plaza de Aragâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=588844694554232&set=o...', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64729400, -0.88478400, '0101000020E610000022C500892650ECBFD272A087DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15294108160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15294108160.webp', 'https://www.flickr.com/photos/zaragozaantigua/15294108160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25497, 'Puerta y paseo de Santa Engracia 1902', 'Fototipia Escolâ”œÃ­. 1902. Al fondo a la derecha, la iglesia de Santa Engracia en todo su volumen.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64752100, -0.88560400, '0101000020E6100000F99D2633DE56ECBF923CD7F7E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895327105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895327105.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895327105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25504, 'Puerta de Santa Engracia c.1900', 'Hauser y Menet. Puerta de Santa Engracia. Ca.1900. Imagen de la Tercera, o "Nueva", Puerta de Santa Engracia. Construida en este nuevo emplazamiento, inmediato a la glorieta de Pignatelli, en 1866, con proyecto de Mariano Lâ”œâ”‚pez. Tenâ”œÂ¡a cinco accesos, peatonales y para tranvâ”œÂ¡as. Muy contestada desde el principio, terminâ”œâ”‚ siendo piqueteada en 1904. Inmediatamente, la plaza recibiâ”œâ”‚ la denominaciâ”œâ”‚n de "Aragâ”œâ”‚n", y se sustituyâ”œâ”‚ la estatua de Pignatelli por la del Justicia. En la imagen, la Puerta de Santa Engracia capturada desde la Glorieta de Pignatelli. De fondo de escenario, la Facultad de Medicina de la Universidad.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15729708458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15729708458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15729708458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25515, 'Puerta de Santa Engracia c.1900', 'Vista de la Puerta de Santa Engracia (1866-1904), con el edificio de Capitanâ”œÂ¡a de la Glorieta de Pignatelli al fondo. Fuente: AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25542484636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25542484636.webp', 'https://www.flickr.com/photos/zaragozaantigua/25542484636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25525, 'Puerta de santa Engracia c.1899', 'Invernal y parcial imagen de la puerta de Santa Engracia capturada desde su exterior con el fondo de la plaza de Aragâ”œâ”‚n, donde a la izquierda destaca la reciente e historicista fachada del edificio de la Capitanâ”œÂ¡a General y la continuaciâ”œâ”‚n hacia el norte con los hotelitos del lado occidental de la plaza. Unos vecinos aprovechan la solanera para hacer el tancredo junto a una de las casetas de consumos ubicada junto a la puerta. En primer tâ”œÂ®rmino, vial por el que circulaban los tranvâ”œÂ¡as a tracciâ”œâ”‚n de sangre de la lâ”œÂ¡nea de Torrero de regreso a la plaza de la Constituciâ”œâ”‚n. Hemos volteado horizontalmente la imagen original para que tenga sentido.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64755000, -0.88548300, '0101000020E61000003A3FC571E055ECBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52033563459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52033563459.webp', 'https://www.flickr.com/photos/zaragozaantigua/52033563459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25919, 'Pl. de Basilio Paraâ”œÂ¡so 1954', 'Imagen capturada desde cierta altura en el colegio del Salvador, con interesante vista del entorno de la plaza de Basilio Paraâ”œÂ¡so en un momento de notable confluencia tranviaria y trolebusera que no parece colapsar mucho la circulaciâ”œâ”‚n rodada: una unidad de la serie 50, con remolque, de la lâ”œÂ¡nea 5 se encamina hacia Venecia; una unidad de la serie 100, con remolque, de la misma lâ”œÂ¡nea desciende hacia Delicias; un trolebâ”œâ•‘s BUT de 1 piso regresa del Terminillo. Pese a todo, el guardia urbano de la ajardinada rotonda permanece atento al trâ”œÃ­nsito Fuente visual: postal de Garcâ”œÂ¡a Garrabella, en www.todocoleccion.net/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31683233400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31683233400.webp', 'https://www.flickr.com/photos/zaragozaantigua/31683233400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25926, 'Pl. de Paraâ”œÂ¡so 1954', 'Imagen capturada desde cierta altura en el colegio del Salvador, con vista del entorno de la plaza de Paraâ”œÂ¡so con su preciosa y florida rotonda central, como lugar de entronque del paseo de Pamplona, paseo de Calvo Sotelo, paseo del General Mola, y paseo de Marina Moreno. Transitan dos unidades de la serie 200, o "rizados", en servicio en la tranviaria lâ”œÂ¡nea 11 "Parque", una en direcciâ”œâ”‚n hacia la plaza Emperador Carlos, y la otra, en primer plano, hacia la terminal de la plaza de Espaâ”œâ–’a. Fuente visual: www.ebay.es/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64730700, -0.88579600, '0101000020E610000008AF5DDA7058ECBF66BCADF4DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34089327660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34089327660.webp', 'https://www.flickr.com/photos/zaragozaantigua/34089327660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25966, 'Plaza de Paraâ”œÂ¡so 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/09/1974. Imagen en altura, desde el Edificio Elâ”œÂ¡seos, de la Plaza de Basilio Paraâ”œÂ¡so, la Plaza de Aragâ”œâ”‚n y el arranque del Paseo de Marina Moreno. Ya estamos en setiembre, pero el verano de este aâ”œâ–’o se prolonga unas semanas mâ”œÃ­s. Se ha secado hasta la fuente de la Plaza. A la derecha mâ”œÃ­s extrema, las tapias que delimitan el solar del volatilizado Colegio de los PP. Jesuâ”œÂ¡tas, en el â”œÂ¡nterin hasta que de ahâ”œÂ¡ salga la nueva sede central de una conocida entidad de ahorro. Al otro lado de Marina Moreno, otras vallas ocultan el solar de un recientemente derribado hotelito de la Plaza de Aragâ”œâ”‚n, el que hacâ”œÂ¡a esquina con la Plaza Paraâ”œÂ¡so, a la espera de que de ahâ”œÂ¡ florezcan hasta 10 alturas en bloque.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64668400, -0.88579900, '0101000020E61000004C8BFA247758ECBF596C938AC6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761852699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761852699.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761852699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25971, 'Av. de Marina Moreno 1963', 'Vista desde cierta altura del arranque de la avenida de Marina Moreno desde la plaza de Basilio Paraâ”œÂ¡so. A la derecha, la mole del colegio de los PP. Jesuitas. A la izquierda, las traseras de los hotelitos de la plaza de Aragâ”œâ”‚n, Santa Engracia y la torre de la Caja de Previsiâ”œâ”‚n Social. Al fondo, la torre de la iglesia de San Miguel. Fuente visual: Archivo Fotogrâ”œÃ­fico Coyne, AHPZ.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64668400, -0.88579900, '0101000020E61000004C8BFA247758ECBF596C938AC6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15005610111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15005610111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15005610111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26066, 'Plaza de Basilio Paraâ”œÂ¡so 1991', 'Imagen capturada desde la notable altura del acristalado y airoso remate del inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, con una vista del entorno de la plaza de Basilio Paraâ”œÂ¡so, en cuyo centro destaca la glorieta central despojada de la mayor parte de su denso jardâ”œÂ¡n de â”œÃ­rboles y arbustos, en el proceso de sustituirlo por una fuente cibernâ”œÂ®tica. A la izquierda, enlace con la plaza de Aragâ”œâ”‚n, donde destaca por su antigua escala la antigua casa de Marcelino Celestino, el â”œâ•‘ltimo de los "hotelitos" que aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a derribado y sustituido por una mole homologada con sus vecinas. De fondo, la gran sede central de una reconocida entidad de ahorro, lindando con el arranque tanto del paseo de las Damas, hacia el fondo, como con la glorieta de Sasera y su referencial gran superficie comercial en altura. A la derecha, el Edificio Elâ”œÂ¡seos chaflanea el arranque del paseo de Sagasta y de la Gran Vâ”œÂ¡a. En primer tâ”œÂ®rmino, escaleras de ingreso al Edificio Paraninfo y el trâ”œÃ­fico rodado canalizado por el paseo de Pamplona. En esta imagen queda claro el oxâ”œÂ¡moron de considerar que la de Basilio Paraâ”œÂ¡so es una plaza. Nunca lo ha sido.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.64731800, -0.88572900, '0101000020E610000014CD0358E457ECBF5A0EF450DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50442708971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50442708971.webp', 'https://www.flickr.com/photos/zaragozaantigua/50442708971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26067, 'Plaza de Basilio Paraâ”œÂ¡so 1992', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, con una vista del entorno de la plaza de Basilio Paraâ”œÂ¡so centrada en el aspecto de la glorieta central tras la instalaciâ”œâ”‚n de una fuente cibernâ”œÂ®tica que, por una parte facilitaba la visibilidad del intenso trâ”œÃ­fico rodado que la circunvalaba diariamente, y por otra "la ionizaciâ”œâ”‚n producida en el aire por el agua es mucho mâ”œÃ­s beneficiosa para la salud pâ”œâ•‘blica que la que pueda obtenerse de una masa vegetal", como se argumentâ”œâ”‚ de forma cientâ”œÂ¡fica para justificar la eliminaciâ”œâ”‚n de la preexistente zona de arbustos y â”œÃ­rboles. Desde ese momento, esta plaza fue uno de los lugares mâ”œÃ­s sanos de la ciudad. Tras la rotonda automovilâ”œÂ¡stica y en el arranque del paseo de la Constituciâ”œâ”‚n, el metâ”œÃ­lico Monumento a la Constituciâ”œâ”‚n de 1978 proyectado por Florencio de Pedro Herrera inaugurado en diciembre de 1989 y que, de puro simbolismo, resulta tal vez demasiado difâ”œÂ¡cil de comprender, algo que deberâ”œÂ¡a estar en la antâ”œÂ¡poda de un texto constitucional.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64733400, -0.88566500, '0101000020E610000065C746205E57ECBF60CB2BD7DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50444382226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50444382226.webp', 'https://www.flickr.com/photos/zaragozaantigua/50444382226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21155, 'La Veneciana 1897', 'Dibujo, publicado en Heraldo de Aragâ”œâ”‚n, del proyecto de fachada principal de la fâ”œÃ­brica de espejos La Veneciana, de Basilio Paraâ”œÂ¡so, sita en el camino de los Cubos, junto a la fundiciâ”œâ”‚n de Pellicer y Juan. Las traseras daban al Huerva, conformando la denominada "curva de La Veneciana" de ese râ”œÂ¡o. Este edificio de Fâ”œÂ®lix Navarro estuvo en pie hasta 1937. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64762800, -0.88839200, '0101000020E6100000A3E5400FB56DECBFA8FC6B79E5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19182456024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19182456024.webp', 'https://www.flickr.com/photos/zaragozaantigua/19182456024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21181, 'Camino de los Cubos 1893', 'Imagen del novâ”œÂ¡simo edificio de la Facultad de Medicina y Ciencias capturado desde el camino de Herederos o de los Cubos, por el que fluye al aire la acequia de la Romareda Baja, junto a la puerta de acceso al Hospital Clâ”œÂ¡nico (en el centro de la imagen) y al original Departamento Anatâ”œâ”‚mico (a la derecha, fuera de plano). Al fondo, a la izquierda, y tras el paseo de la Lealtad, el tambiâ”œÂ®n reciente edificio de la Capitanâ”œÂ¡a General de la plaza de Aragâ”œâ”‚n. Fuente visual: fotografâ”œÂ¡a de Lucas Escolâ”œÃ­ Arimany recogida en Hilariâ”œâ”‚n y Enrique Villuendas (secciâ”œâ”‚n Fotomicrogrâ”œÃ­fica de la Facultad de Medicina), "â”œÃ¼lbum fotogrâ”œÃ­fico realizado con motivo de la inauguraciâ”œâ”‚n del edificio de la Facultad de Medicina y Ciencias". Colegio Oficial de Arquitectos de Aragâ”œâ”‚n. Reproducida en la exposiciâ”œâ”‚n "Historia, conocimiento y patrimonio, 475 aniversario del privilegio fundacional de la Universidad de Zaragoza, Vicerrectorado de Cultura y Proyecciâ”œâ”‚n Social-Universidad de Zaragoza.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64759200, -0.88826000, '0101000020E6100000EA094B3CA06CECBF5C936E4BE4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33966331253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33966331253.webp', 'https://www.flickr.com/photos/zaragozaantigua/33966331253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21182, 'Camino de los Cubos 1893', 'Imagen del novâ”œÂ¡simo palacio de las Facultades de Medicina y Ciencias, centrada en el tercero de los edificios de que constaba, el departamento de Disecciâ”œâ”‚n o Anfiteatro anatâ”œâ”‚mico. La captura se ha realizado desde la altura del inmediato Hospital clâ”œÂ¡nico. Al fondo, las arboladas mâ”œÃ­rgenes del râ”œÂ¡o Huerva, con vista parcial de la fâ”œÃ­brica de sombreros de Desiderio Casanava, en el camino de los Cubos. Inmediata a la derecha, en el mismo camino, carpinterâ”œÂ¡a y fâ”œÃ­brica de hielo. Tras ella, aâ”œâ–’os despuâ”œÂ®s se instalarâ”œÂ¡a la Fundiciâ”œâ”‚n de Pellicer y Juan, y la fâ”œÃ­brica de cristales de la Veneciana. Fuente visual: fotografâ”œÂ¡a de Lucas Escolâ”œÃ­ Arimany recogida en Hilariâ”œâ”‚n y Enrique Villuendas (secciâ”œâ”‚n Fotomicrogrâ”œÃ­fica de la Facultad de Medicina), "â”œÃ¼lbum fotogrâ”œÃ­fico realizado con motivo de la inauguraciâ”œâ”‚n del edificio de la Facultad de Medicina y Ciencias". Colegio Oficial de Arquitectos de Aragâ”œâ”‚n. Reproducida en la exposiciâ”œâ”‚n "Historia, conocimiento y patrimonio, 475 aniversario del privilegio fundacional de la Universidad de Zaragoza, Vicerrectorado de Cultura y Proyecciâ”œâ”‚n Social-Universidad de Zaragoza.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64690300, -0.88813100, '0101000020E6100000740AF2B3916BECBF9757AEB7CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34007036663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34007036663.webp', 'https://www.flickr.com/photos/zaragozaantigua/34007036663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21366, 'Velâ”œâ”‚dromo Campos Elâ”œÂ¡seos 1915', 'Interior del velâ”œâ”‚dromo de los Campos Elâ”œÂ¡seos, en la confluencia del paseo de Sagasta y el cauce al aire del râ”œÂ¡o Huerva. Al fondo, edificio del arranque de los nâ”œâ•‘meros pares del paseo de Sagasta. Fuente visual: El fotâ”œâ”‚grafo Luis Gandâ”œâ•‘ Mercadal. Una crâ”œâ”‚nica visual 1910-1830.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14979092707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14979092707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14979092707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21393, 'Velâ”œâ”‚dromo Campos Elâ”œÂ¡seos 1915', '"Los deportes en Zaragoza. Calderâ”œâ”‚n, salto de altura". Aspecto del Velâ”œâ”‚dromo de los Campos Elâ”œÂ¡seos de Zaragoza, con el râ”œÂ¡o Huerva a la izquierda y la actual plaza de Paraâ”œÂ¡so al fondo. La entrada se realizaba por el chaflâ”œÃ­n entre la Gran Vâ”œÂ»a y el paseo Sagasta actuales. Fue inaugurado en 1895 y derribado en 1920. Fuente: Fotografâ”œÂ¡a de Aurelio Grasa publicada en Heraldo de Aragâ”œâ”‚n el 7 de julio de 1915, junto a una composiciâ”œâ”‚n de otras tres fotografâ”œÂ¡as. Fue publicada en la pâ”œÃ­gina 61 del catâ”œÃ­logo "Aurelio Grasa reportero grâ”œÃ­fico 1910-1917", RSFZ, Galerâ”œÂ¡a Costa, 3. Zaragoza 2003. www.aureliograsa.es Tomada de www.facebook.com/photo.php?fbid=896176007071692&set=g...', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21224325020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21224325020.webp', 'https://www.flickr.com/photos/zaragozaantigua/21224325020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21493, 'Paseo de Pamplona aâ”œâ–’os 20', 'AHPZ. Gabriel Faci. Aâ”œâ–’os 20. "Calles nevadas." Interesante perspectiva, tras una nevada, del Paseo de Pamplona, en su confluencia con la Plaza de Paraâ”œÂ¡so. El Paseo presenta su andador central, con bancos y â”œÃ­rboles, y el Monumento a la Expo 1908, allâ”œÂ¡ instalado desde 1910. Los edificios de vivienda de la izquierda seâ”œâ–’alan dâ”œâ”‚nde desemboca el camino de Herederos (aâ”œâ–’os mâ”œÃ­s tarde Doctor Cerrada), por el que fluâ”œÂ¡a la acequia de la Romareda. A la derecha, el edificio de Capitanâ”œÂ¡a, y las calles de Valencia (luego, de Ponzano) y de Teruel (luego, de Bilbao), con vista, en primer lugar, de la fâ”œÃ­brica de conservas alimenticias "Bescâ”œâ”‚s Hermanos", y detrâ”œÃ­s, el colegio de las Esclavas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.64783100, -0.88631900, '0101000020E61000007D59DAA9B95CECBFE02A4F20ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15252466290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15252466290.webp', 'https://www.flickr.com/photos/zaragozaantigua/15252466290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21614, 'Cubrimiento Huerva 1925', 'Imagen del cubrimiento del râ”œÂ¡o Huerva en su urbano tramo entre la curva de "La Veneciana", cuyas instalaciones destacan al fondo, y el puente de Santa Engracia, desde donde se ha realizado esta captura. A la izquierda, el circuito del antiguo velâ”œâ”‚dromo, y el arranque del camino del Sâ”œÃ­bado. A la derecha, el Hospital Clâ”œÂ¡nico y la Facultad de Medicina y Ciencias. Al fondo, la fâ”œÃ­brica de sombreros de Gregorio Hernâ”œÃ­ndez, junto a la zanja del ferrocarril de la lâ”œÂ¡nea MZA. Destaca la notable diferencia de cota entre una y otra orilla del râ”œÂ¡o, que el cubrimiento nivelarâ”œÃ­ adecuadamente. Fuente visual: â”œÃ¼ngel Aâ”œÂ¡sa y Hermanos.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64664600, -0.88682200, '0101000020E61000002CF2EB87D860ECBF6B0BCF4BC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31656822710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31656822710.webp', 'https://www.flickr.com/photos/zaragozaantigua/31656822710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21616, 'Cubrimiento Huerva 1926', 'Imagen realizada durante las obras de cubrimiento del râ”œÂ¡o Huerva en su primer tramo urbano, entre la "curva de la Veneciana" y el puente de Santa Engracia. La captura se ha realizado junto a la facultad de Medicina y Ciencias, con los edificios de las clâ”œÂ¡nicas universitarias al fondo, muy cerca ya del puente. Este tramo fue denominado "Gran Vâ”œÂ¡a", pero tras el golpe del 18 de julio de 1936 serâ”œÃ­ cambiado por los afines al nuevo Râ”œÂ®gimen como "avenida de Calvo Sotelo", hasta la recuperaciâ”œâ”‚n de la democracia local en 1979. Fuente visual: â”œÃ¼ngel Aâ”œÂ¡sa y Hermano.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64680300, -0.88659900, '0101000020E61000005D52B5DD045FECBF33FAD170CAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31946689646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31946689646.webp', 'https://www.flickr.com/photos/zaragozaantigua/31946689646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21731, 'Pl. de Basilio Paraâ”œÂ¡so 1936', '12 de octubre de 1936. Celebraciâ”œâ”‚n del Dâ”œÂ¡a de la Raza y de la fiesta de la Virgen del Pilar. Las calles de la ciudad fueron escenario de interesantes manifestaciones varias, incluyendo el de la precipitaciâ”œâ”‚n en forma de lluvia. Catâ”œâ”‚licos y patriâ”œâ”‚ticos falangistas, carlistas y renovadores espaâ”œâ–’oles, portando banderas propias, alemanas, italianas y portuguesas, desfilaron y procesionaron acompaâ”œâ–’ados de mâ”œâ•‘sicas militares desde distintos puntos hasta el escenario central establecido câ”œâ”‚mo no en la plaza del Pilar. Esta imagen forma parte de una serie de tres, en la que se documenta grâ”œÃ­ficamente esta concentraciâ”œâ”‚n y posterior desfile de miembros de la Falange, partiendo desde la puerta de la facultad de Medicina y Ciencias, que centra esta escena representativa de la Zaragoza de la â”œÂ®poca.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21321647900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21321647900.webp', 'https://www.flickr.com/photos/zaragozaantigua/21321647900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21736, 'Pl. de Basilio Paraâ”œÂ¡so 1936', '12 de octubre de 1936. Celebraciâ”œâ”‚n del Dâ”œÂ¡a de la Raza y de la fiesta de la Virgen del Pilar. Las calles de la ciudad fueron escenario de manifestaciones varias, incluyendo el de la precipitaciâ”œâ”‚n en forma de lluvia. Catâ”œâ”‚licos y patriâ”œâ”‚ticos falangistas, carlistas y renovadores espaâ”œâ–’oles, con banderas (propias, alemanas, italianas y portuguesas) y mâ”œâ•‘sicas, desfilaron y procesionaron desde distintos puntos hasta el escenario central de la plaza del Pilar. Imagen de una serie de tres, en la que se documenta la concentraciâ”œâ”‚n y posterior desfile de miembros de la Falange, partiendo de la puerta de la facultad de Medicina y Ciencias, desde donde estâ”œÃ­ tomada la foto. A la izquierda, edificio de Capitanâ”œÂ¡a. Al fondo, iglesia de Santa Engracia. Fuente visual: Archivo Digital Nacional, Polonia. www.nac.gov.pl/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21483618296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21483618296.webp', 'https://www.flickr.com/photos/zaragozaantigua/21483618296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21737, 'Pl. de Basilio Paraâ”œÂ¡so 1936', 'Bajo pertinaz lluvia, celebraciâ”œâ”‚n del Dâ”œÂ¡a de la Raza y de la fiesta de la Virgen del Pilar. Militantes de Falange Espaâ”œâ–’ola, Renovaciâ”œâ”‚n Espaâ”œâ–’ola y carlistas con banderas propias, ademâ”œÃ­s de la alemana, italiana y portuguesa y con marciales mâ”œâ•‘sicas, desfilaron desde distintos puntos hasta el escenario central de la plaza del Pilar. En la imagen, abanderadas de la Secciâ”œâ”‚n Femenina de Falange con el fondo de la facultad de Medicina y Ciencias. Fuente visual: Archivo Digital Nacional, Polonia. www.nac.gov.pl/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21498762552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21498762552.webp', 'https://www.flickr.com/photos/zaragozaantigua/21498762552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21963, 'Pl. de Basilio Paraâ”œÂ¡so 1949', 'Recreaciâ”œâ”‚n de la plaza de Basilio Paraâ”œÂ¡so de Zaragoza en 1949, con la Facultad de Medicina y Ciencias al fondo. Dibujo de Vâ”œÂ¡ctor M. Lahuerta con guion de Emilio Alfaro para esta primera viâ”œâ–’eta de la historieta "Doctor Garcâ”œÂ¡a", 1981. Fuente: "El â”œâ•‘ltimo nombre. Miguel Labordeta", IFC, 2015.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.64750900, -0.88605200, '0101000020E6100000C5C551B9895AECBFCE6E2D93E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21163914405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21163914405.webp', 'https://www.flickr.com/photos/zaragozaantigua/21163914405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21992, 'Pl. de Basilio Paraâ”œÂ¡so 1944', 'Imagen capturada durante la lectura del doctor Julio Ariâ”œâ–’o Cenzano de su discurso de ingreso en la Real Academia de Medicina de Zaragoza, en la Facultad de Medicina y Ciencias sita en la plaza de Paraâ”œÂ¡so. Este doctor zaragozano se especializâ”œâ”‚ en otorrinolaringologâ”œÂ¡a, y creâ”œâ”‚ el servicio de esta especialidad mâ”œÂ®dica en el hospital provincial de Nâ”¬Â¬ Sâ”¬Â¬ de Gracia. Fuente visual: Foto Lozano, en www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64727500, -0.88691100, '0101000020E610000014CE6E2D9361ECBF5B423EE8D9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30898410605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30898410605.webp', 'https://www.flickr.com/photos/zaragozaantigua/30898410605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22079, 'P.â”¬â•‘ de Pamplona 1958', 'Câ”œÂ®sar Gracia Jarque. 1958. "Paseo de Pamplona." Imagen capturada desde el Edificio de Elâ”œÂ¡seos, chaflanero entre Calvo Sotelo, la Plaza de Paraâ”œÂ¡so, y el arranque del paseo del general Mola. El paseo de Pamplona, aâ”œâ•‘n con andador central arbolado. Al fondo, sin barreras arquitectâ”œâ”‚nicas, la visual alcanza hasta el Convento de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64793500, -0.88637300, '0101000020E610000049D6E1E82A5DECBF8577B988EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754353817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754353817.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754353817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22117, 'P.â”¬â•‘ de Calvo Sotelo 1953', 'Imagen del andamiaje de obra tras el que se estaba construyendo el bloque del nâ”¬â•‘ 18 (actual 34) del paseo de Calvo Sotelo, chaflanero con la calle Dato (izquierda), y con proyecto de Josâ”œÂ® Descartâ”œÂ¡n Burillo. Este paseo conservarâ”œÃ­ esta denominaciâ”œâ”‚n oficial hasta 1979. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64613300, -0.88874300, '0101000020E6100000D190F1289570ECBFE5EE737CB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500438876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500438876.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500438876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22139, 'P.â”¬â•‘ de Calvo Sotelo 1953', 'Tranvâ”œÂ¡a nâ”¬â•‘ 160 se servicio en la lâ”œÂ¡nea de Casablanca transitando por el paseo de Calvo Sotelo, el 11 de mayo de 1953. Al fondo, plaza de Paraâ”œÂ¡so. Fuente visual: "Los tranvâ”œÂ¡as de Zaragoza", J. Peâ”œâ–’a - J. M. Valero, DPZ, 1985.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64680300, -0.88659900, '0101000020E61000005D52B5DD045FECBF33FAD170CAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24851870335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24851870335.webp', 'https://www.flickr.com/photos/zaragozaantigua/24851870335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
