INSERT INTO public.photos VALUES (22322, 'Plaza de Paraâ”œÂ¡so 1969', 'Un momento de pâ”œÃ­nico controlado: mientras reparan algâ”œâ•‘n desperfecto cerca de la vâ”œÂ¡a tranviaria, el trâ”œÃ­fico rodado en la plaza de Paraâ”œÂ¡so se pone en Defcon 3, porque aunque la plaza de Espaâ”œâ–’a siga emperrada en ser el "centro", el verdadero poder (cuando menos, en tâ”œÂ®rminos de regulaciâ”œâ”‚n circulatoria) reside en este gran â”œâ”‚valo donde confluyen hasta cinco arterias vitales de la ciudad. Mientras los tranvâ”œÂ¡as aguardan (el 11 al Parque, el 5, a Torrero), la circulaciâ”œâ”‚n rodada se regula mediante trapo, mientras llega el seâ”œâ–’or del silbato. Es casi seguro que ya hay reporteros anunciando grandes cataclismos câ”œâ”‚smicos por el "suceso", y repitiendo cuales cotorras que son la consigna de "caâ”œâ–’a al tranvâ”œÂ¡a". Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64765600, -0.88593100, '0101000020E61000000667F0F78B59ECBF72874D64E6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15876637252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15876637252.webp', 'https://www.flickr.com/photos/zaragozaantigua/15876637252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
