INSERT INTO public.photos VALUES (22644, 'Facultad de Medicina 1971', 'Foto: Gerardo Sancho. Fila para la vacunaciâ”œâ”‚n contra el câ”œâ”‚lera, en las escaleras de la Facultad de Medicina y Ciencias de Zaragoza, el 20 de julio de 1971. La epidemia se extendiâ”œâ”‚ por Zaragoza, Barcelona, Valencia y Murcia. Fuente: AMZ.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64738900, -0.88649200, '0101000020E6100000DB4C8578245EECBF23658BA4DDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20571413533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20571413533.webp', 'https://www.flickr.com/photos/zaragozaantigua/20571413533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22828, 'Plaza de Basilio Paraâ”œÂ¡so 1970', 'Tremendo pozo excavado en el entorno de la plaza de Basilio Paraâ”œÂ¡so por la empresa Elâ”œÂ®ctricas Reunidas de Zaragoza SA al objeto de construir la subterrâ”œÃ­nea SET (Subestaciâ”œâ”‚n Elâ”œÂ®ctrica Transformadora) "Paraâ”œÂ¡so" con la que mejor atender sus necesidades de negocio en el centro de la ciudad. En primer tâ”œÂ®rmino la maquinaria trabaja extrayendo tierra mientras al fondo la circulaciâ”œâ”‚n rodada transita por el paseo de Pamplona.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64719700, -0.88605100, '0101000020E6100000AFD172A0875AECBFDF88EE59D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52853380244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52853380244.webp', 'https://www.flickr.com/photos/zaragozaantigua/52853380244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22993, '&quot;Leâ”œâ”‚n&quot; de Rallo, 1990', 'Imagen durante el proceso de modelado de los monumentales "Leones del Puente de Piedra": realizada la figura en arcilla, va a comenzar el "vaciado" en escayola. Luego serâ”œÃ­ fundido en bronce, en Valls (Tarragona). Este proyecto estaba asociado con la reforma del puente de Piedra acometida entre 1989 y 1991 por Josâ”œÂ® Manuel Pâ”œÂ®rez Latorre. Junto a Francisco Rallo Lahoz (con las manos en la escayola), autor de esta camada de broncâ”œÂ¡neos felinos, su hijo Paco Rallo Gâ”œâ”‚mez, y Fernando Cortâ”œÂ®s. El provisional taller es una de las antiguas aulas de la Facultad de Medicina y Ciencias, antes de su rehabilitaciâ”œâ”‚n. Los originales leones del puente de Piedra, dos parejas de gatillos tallados en piedra barroca a mediados del XVII, ejercieron de originales "guardianes del puente" hasta que una intervenciâ”œâ”‚n realizada al hilo de la Expo Hispano-Francesa de 1908 se los llevâ”œâ”‚ allâ”œÃ­ por donde anda la Torre Nueva, y la puerta del Duque, entre otras. Fuente visual: Foto Gonzalo Bullâ”œâ”‚n, en "Revista Rolde".', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64719400, -0.88688000, '0101000020E6100000533F6F2A5261ECBF6E15C440D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21679214183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21679214183.webp', 'https://www.flickr.com/photos/zaragozaantigua/21679214183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23036, 'Gran Vâ”œÂ¡a 1992', 'Manifestaciâ”œâ”‚n contra el racismo y la xenofobia celebrada el 29 de noviembre de 1992, a su paso por el arranque de la Gran Vâ”œÂ¡a desde la cercana glorieta de Sasera, donde iniciâ”œâ”‚ su recorrido. Fue convocada por la Coordinadora Antirracista, que aglutinaba a prâ”œÃ­cticamente todas las asociaciones zaragozanas y grupos polâ”œÂ¡ticos de izquierda, y fue secundada por unas 10.000 personas. El detonante de la respuesta social en toda Espaâ”œâ–’a fue el asesinato racista en el distrito de Aravaca de Madrid de la dominicana Lucrecia Pâ”œÂ®rez, por parte del guardia civil Luis Merino, cometido el 13 de noviembre. Dâ”œÂ¡as antes de la marcha, en la plaza de los Sitios, unos jâ”œâ”‚venes neonazis habâ”œÂ¡an agredido a un grupo de mendigos.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64698000, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF42959A3DD0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50367962093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50367962093.webp', 'https://www.flickr.com/photos/zaragozaantigua/50367962093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23191, 'Gran Vâ”œÂ¡a 2010', 'Obras de reforzamiento del cubrimiento del râ”œÂ¡o Huerva, a su paso por la Gran Vâ”œÂ¡a de Zaragoza. A la derecha, el puente de Santa Engracia. Al fondo, la plaza de Paraâ”œÂ¡so. Fuente: www.elperiodicodearagon.com/', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64688400, -0.88622400, '0101000020E61000000DC51D6FF25BECBF20274C18CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19668020719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19668020719.webp', 'https://www.flickr.com/photos/zaragozaantigua/19668020719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23192, 'Gran Vâ”œÂ¡a 2010', 'Imagen virtual de â”œÃ¼ngel Hernâ”œÃ­ndez, 2010. Recreaciâ”œâ”‚n artâ”œÂ¡stica del râ”œÂ¡o Huerva a su paso por la Gran Vâ”œÂ¡a de Zaragoza, visto desde la plaza de Paraâ”œÂ¡so. La propuesta no prosperâ”œâ”‚. Fuente: www.heraldo.es', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64688400, -0.88622400, '0101000020E61000000DC51D6FF25BECBF20274C18CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19730233199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19730233199.webp', 'https://www.flickr.com/photos/zaragozaantigua/19730233199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23643, 'Gran Vâ”œÂ¡a 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1966. Imagen de las faenas de plantado arbustâ”œÂ¡fero en el paseo central de la Gran Vâ”œÂ¡a, muy cerca de la plaza de Paraâ”œÂ¡so. Enfrente, el solar del actual nâ”¬â•‘ 24. A la derecha, la entonces Jefatura de servicios y del sector Aâ”œÂ®reo del Ejâ”œÂ®rcito del Aire.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64647600, -0.88735500, '0101000020E610000085251E503665ECBF0FD3BEB9BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718346822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718346822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718346822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24032, 'Clâ”œÂ¡nicas Universitarias 1919', 'Imagen de la inauguraciâ”œâ”‚n del monumento al decano de la Facultad de Medicina, Hipâ”œâ”‚lito Fairâ”œÂ®n y Andrâ”œÂ®s, ubicado en la plaza entre la puerta principal de las Clâ”œÂ¡nicas Universitarias, y la original Facultad de Medicina, entre el camino de los Cubos y el cauce al aire del râ”œÂ¡o Huerva. Este ilustre doctor falleciâ”œâ”‚ un aâ”œâ–’o antes, el busto era obra del escultor Josâ”œÂ® Bueno, y al acto acudiâ”œâ”‚ una selecta representaciâ”œâ”‚n de la comunidad universitaria, (con el rector y el decano al frente), de la ciudad (con el alcalde Pedro Calvo Olivares), y de otras entidades. Este monumento fue desmontado aâ”œâ–’os despuâ”œÂ®s, aunque al menos se conserva el busto, como parte integrante del patrimonio artâ”œÂ¡stico de la Universidad de Zaragoza. Fuente visual: Foto Sancho Mercadâ”œÂ®, "La Hormiga de Oro".', 1919, 1919, 1919, 'Anos 10', 'CENTRO', 41.64711100, -0.88747700, '0101000020E61000005B785E2A3666ECBFE1F08288D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26349267862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26349267862.webp', 'https://www.flickr.com/photos/zaragozaantigua/26349267862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24098, 'Facultad de Medicina y Ciencias 1917', 'Imagen capturada tras el incendio que el 20 de julio de 1917 se iniciâ”œâ”‚ de madrugada en el laboratorio de quâ”œÂ¡mica inorgâ”œÃ­nica y que asolâ”œâ”‚ la Facultad de Medicina y Ciencias, centrada en el estado en que quedâ”œâ”‚ el Museo de Botâ”œÃ­nica. El retâ”œÂ®n de bomberos, ademâ”œÃ­s de guardiaciviles, y militares de los cuerpos de ingenieros pontoneros y de infanterâ”œÂ¡a movilizados para la ocasiâ”œâ”‚n por las deficiencias del servicio municipal de bomberos, atajaron el fuego asesorados por el arquitecto Yarza. Se dio la circunstancia de que las bocas de riego de la Facultad no coincidâ”œÂ¡an con el diâ”œÃ­metro de las mangueras de los bomberos, por lo que hubo que bombear el agua desde la inmediata acequia de la Romareda que fluâ”œÂ¡a al aire por el camino de los Cubos. En la escena y con una manguera se escenifica para la prensa grâ”œÃ­fica el control de un incendio ya extinguido con anterioridad, mientras una pareja de guardiaciviles permanece a la sombra. Una secciâ”œâ”‚n de ingenieros pontoneros y un retâ”œÂ®n de bomberos permanecieron durante la noche como medida de precauciâ”œâ”‚n.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64729400, -0.88697400, '0101000020E6100000ADDF4C4C1762ECBFD272A087DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50132907851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50132907851.webp', 'https://www.flickr.com/photos/zaragozaantigua/50132907851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24119, 'Facultad de Medicina 1916', 'Tras la caâ”œÂ¡da de la colonia alemana del Camerâ”œâ•‘n en manos aliadas en enero de 1916, un millar de militares y civiles alemanes se refugiaron en la Guinea espaâ”œâ–’ola, acompaâ”œâ–’ados de unos 45.000 indâ”œÂ¡genas cameruneses, aunque mâ”œÃ­s de la mitad de estos â”œâ•‘ltimos fueron inmediatamente devueltos a Camerâ”œâ•‘n. Bajo presiâ”œâ”‚n de los aliados se condujo a los alemanes a la Penâ”œÂ¡nsula para ser internados bajo la promesa de no salir de sus destinos de residencia hasta el fin de la guerra. De los 856 llegados a Espaâ”œâ–’a 347 se instalaron en Zaragoza, revolucionando la sociedad local de la â”œÂ®poca. Aunque la mayor parte de ellos regresaron a Alemania tras la derrota de 1918, un contingente no determinado optâ”œâ”‚ por quedarse. Poco despuâ”œÂ®s de su llegada a Zaragoza, la Universidad decidiâ”œâ”‚ establecer cursos de castellano para alemanes, a impartir en el edificio de la Facultad de Medicina y Ciencias, de cuatro a cinco de la tarde, dividiendo a los inscritos segâ”œâ•‘n tuvieran o no estudios de latâ”œÂ¡n. En la imagen, posado colectivo en las escaleras de acceso a la facultad de algunos de los alemanes inscritos a estos cursos.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64751000, -0.88645900, '0101000020E6100000EDD5C743DF5DECBF9EEA909BE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459621636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459621636.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459621636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24264, 'Camino de los Cubos 1890', 'Panorâ”œÃ­mica capturada desde la altura de la nueva Facultad de Medicina y Ciencias, orientada hacia los terrenos entre el râ”œÂ¡o Huerva y el camino de los Cubos junto a la acequia Baja de la Romareda. Al fondo, tras la torre de Fita, la fâ”œÃ­brica de sombreros de Desiderio Casanava, que ya en el siglo XX pasarâ”œÃ­ a ser propiedad de Gregorio Hernâ”œÃ­ndez. A la derecha, camino de los Capuchinos. Fuente visual: "Vista de la Vega de Zaragoza", fototipia de Joarizti y Mariezcurrena, en Ã”Ã‡Â£Zaragoza Artâ”œÂ¡stica, Monumental e Histâ”œâ”‚ricaÃ”Ã‡Ã˜, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64670500, -0.88867100, '0101000020E61000006CEA3C2AFE6FECBF7094BC3AC7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33221020491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33221020491.webp', 'https://www.flickr.com/photos/zaragozaantigua/33221020491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24265, 'Gran Vâ”œÂ¡a 1931', 'Invernal imagen de la prâ”œÂ¡stina Gran Vâ”œÂ¡a, apenas comenzada a urbanizar tras las obras de cubrimiento del râ”œÂ¡o Huerva, en una luminosa captura de Lucien Roisin de su andador central y su fachada norte, con la facultad de Medicina y Ciencias en primer tâ”œÂ®rmino, y despuâ”œÂ®s, los pabellones de las Clâ”œÂ¡nicas universitarias, el pionero bloque de viviendas del actual nâ”¬â•‘ 22, y la fâ”œÃ­brica de la Veneciana, terminando, al fondo, con algunos de los pâ”œÂ¼oneros bloques del ensanche de Miralbueno, al otro lado de la trinchera del ferrocarril a Barcelona. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64664600, -0.88682200, '0101000020E61000002CF2EB87D860ECBF6B0BCF4BC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33341897190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33341897190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33341897190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24709, 'Grupo Vizconde Escoriaza 1991', 'Imagen capturada en el interior del grupo de viviendas o barriada "Vizconde de Escoriaza" proyectada por el arquitecto Miguel Beltrâ”œÃ­n. La escena se centra en los edificios exentos de la capilla dedicada a la Virgen de Santa Rosa de Lima, y la anexa escuela segregada para niâ”œâ–’os y para niâ”œâ–’as, que se ubicaron en el centro de la barriada. A pesar de que este espacio interior, al que se accede por la calle de Fray Luis Urbano, estaba proyectado como zona verde y de recreo, esto no se realizâ”œâ”‚ nunca, quedando como la explanada de tierra que figura en la fotografâ”œÂ¡a. En 1995, la Fundaciâ”œâ”‚n Tranvâ”œÂ¡a, en colaboraciâ”œâ”‚n con la Asociaciâ”œâ”‚n de Vecinos, rehabilitarâ”œÂ¡a este equipamiento religioso y escolar en desuso, que ademâ”œÃ­s se habâ”œÂ¡a convertido en un foco conflictivo del barrio de Las Fuentes, como Centro de Recursos Bâ”œÃ­sicos que actualmente ejerce de Centro de Recursos Comunitarios.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64831200, -0.85833900, '0101000020E6100000F833BC598377EBBF5BCD3AE3FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449886923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449886923.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449886923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24268, 'Velâ”œâ”‚dromo de los Campos Elâ”œÂ¡seos 1895', 'Dibujo realizado poco despuâ”œÂ®s de la inauguraciâ”œâ”‚n del flamante velâ”œâ”‚dromo de los Campos Elâ”œÂ¡seos, construido en terrenos de la antigua adula del Miâ”œÂ®rcoles, entre el cauce al aire del râ”œÂ¡o Huerva y el arranque del ensanche vertebrado por el paseo de Sagasta. Durante las â”œâ•‘ltimas dâ”œÂ®cadas del siglo XIX esta ribereâ”œâ–’a ubicaciâ”œâ”‚n conociâ”œâ”‚ diversos usos recreativos y de ocio, fue sede del provisional Teatro de los Campos Elâ”œÂ¡seos (1875-1880), solar de algâ”œâ•‘n itinerante circo, y hasta ocasional plaza de toros. En 1895 fue construido un recinto para usuarios de velocâ”œÂ¡pedos, en uso hasta la construcciâ”œâ”‚n del un velâ”œâ”‚dromo mâ”œÃ­s moderno localizado terrazas arriba, en Torrero, a finales de los aâ”œâ–’os veinte del pasado siglo. A la izquierda, el novâ”œÂ¡simo edificio de las Facultades de Medicina y Ciencias y de la Escuela de Artes y Oficios. Al fondo, el imponente Colegio del Salvador y el arbolado arranque de los paseos de las Damas y de Sagasta. Fuente visual: AMZ; en Amparo Martâ”œÂ¡nez Herranz, La arquitectura teatral en Zaragoza, IFC, 2003.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44448834351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44448834351.webp', 'https://www.flickr.com/photos/zaragozaantigua/44448834351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24269, 'Facultad de Medicina 1931', 'Imagen capturada en la altura del Observatorio Oficial del Servicio Meteorolâ”œâ”‚gico Nacional, instalado en la Facultad de Medicina y Ciencias de la Universidad, durante la realizaciâ”œâ”‚n de un matinal sondeo aerolâ”œâ”‚gico que incluye la utilizaciâ”œâ”‚n de un globo. Este observatorio habâ”œÂ¡a sustituido al establecido originalmente en el colegio de las Escuelas Pâ”œÂ¡as.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64721400, -0.88725300, '0101000020E610000075E448676064ECBFB5C189E8D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52520532294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52520532294.webp', 'https://www.flickr.com/photos/zaragozaantigua/52520532294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
